module mux_4_to_1 (
    input wire [3:0] input_data,
    input wire [1:0] sel,
    input wire enable,
    output reg data_out
);
    always @(*) begin
        if (enable) begin
            case (sel)
                2'b00: data_out = input_data[0];
                2'b01: data_out = input_data[1];
                2'b10: data_out = input_data[2];
                2'b11: data_out = input_data[3];
                default: data_out = 1'b0; // default case
            endcase
        end else begin
            data_out = 1'b0; // output zero if enable is low
        end
    end
endmodule
